// deriveBreadcrumb retorna o breadcrumb a partir do ShellConfig.
// Se Breadcrumb está explícito, usa-o; caso contrário deriva de ActivePage.
func deriveBreadcrumb(config ShellConfig) []string {
	if len(config.Breadcrumb) > 0 {
		return config.Breadcrumb
	}
	switch config.ActivePage {
	case "dashboard":
		return []string{"Hoje"}
	case "patients":
		return []string{"Pacientes"}
	case "new-patient":
		return []string{"Pacientes", "Novo Paciente"}
	case "agenda":
		return []string{"Agenda"}
	case "patient-summary", "patient-anamnesis", "patient-history", "patient-goals":
		if config.PageTitle != "" {
			return []string{"Pacientes", config.PageTitle}
		}
		return []string{"Pacientes"}
	default:
		if config.PageTitle != "" {
			return []string{config.PageTitle}
		}
		return []string{"Arandu"}
	}
}

// userInitials extrai até 2 iniciais de um email para o avatar.
func userInitials(email string) string {
	if email == "" {
		return "?"
	}
	prefix := email
	if idx := strings.Index(email, "@"); idx > 0 {
		prefix = email[:idx]
	}
	parts := strings.FieldsFunc(prefix, func(r rune) bool {
		return r == '.' || r == '_' || r == '-'
	})
	if len(parts) >= 2 && len(parts[0]) > 0 && len(parts[1]) > 0 {
		return strings.ToUpper(string(parts[0][0])) + strings.ToUpper(string(parts[1][0]))
	}
	if len(prefix) >= 2 {
		return strings.ToUpper(prefix[:2])
	}
	return strings.ToUpper(prefix)
}

